// Auth middleware: extracts session from headers via better-auth
export const authMiddleware = baseWithMeta.middleware(async ({ context, next }) => {
  const sessionData = await auth.api.getSession({ headers: context.headers || {} });
  if (!sessionData?.session || !sessionData?.user) throw new ORPCError("UNAUTHORIZED", {...});
  return next({ context: { session, subordinateCache, user } satisfies AuthContext });
});

// Protected procedure: base + auth + permission check
export const protectedProcedure = baseWithMeta
  .use(authMiddleware)
  .use(async ({ context, next, procedure }) => {
    const required = procedure["~orpc"].meta.permission;
    if (!required) return next();
    if (context.user.permissions.includes(`${required.resource}:${required.action}`)) return next();
    throw new ORPCError("FORBIDDEN", { ... });
  });
```

